import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "@/hooks/use-toast";
import { useTranslation } from "react-i18next";

export interface NearbyFoodPinRow {
  id: string;
  restaurant_id: string;
  sort_order: number;
  note: string | null;
  created_by: string | null;
  created_at: string;
  updated_at: string;
  restaurants?: {
    id: string;
    name: string;
    name_en?: string | null;
    name_pt?: string | null;
    image_url?: string | null;
    lat: number;
    lng: number;
    city?: string | null;
    address?: string | null;
    visible?: boolean;
    archived?: boolean;
    store_level?: string | null;
    template?: string | null;
    type_en?: string[] | null;
    michelin_stars?: string | null;
  } | null;
}

const PINS_QUERY_KEY = ["nearby-food-pins"];

export function useNearbyFoodPinsAdmin() {
  const queryClient = useQueryClient();
  const { t } = useTranslation();

  const list = useQuery({
    queryKey: PINS_QUERY_KEY,
    queryFn: async (): Promise<NearbyFoodPinRow[]> => {
      const { data, error } = await supabase
        .from("nearby_food_pins")
        .select("*, restaurants:restaurant_id (id,name,name_en,name_pt,image_url,lat,lng,city,address,visible,archived,store_level,template,type_en,michelin_stars)")
        .order("sort_order", { ascending: true })
        .order("created_at", { ascending: false });
      if (error) throw error;
      return (data || []) as any;
    },
  });

  const add = useMutation({
    mutationFn: async (input: { restaurant_id: string; sort_order?: number; note?: string | null }) => {
      const { data: userData } = await supabase.auth.getUser();
      const { error } = await supabase.from("nearby_food_pins").insert({
        restaurant_id: input.restaurant_id,
        sort_order: input.sort_order ?? 0,
        note: input.note ?? null,
        created_by: userData.user?.id ?? null,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: PINS_QUERY_KEY });
      toast({ title: t("admin.nearbyFoodPins.added") });
    },
    onError: (err: any) => {
      const msg = err?.message?.includes("duplicate")
        ? t("admin.nearbyFoodPins.duplicate")
        : err?.message || "Error";
      toast({ title: msg, variant: "destructive" });
    },
  });

  const update = useMutation({
    mutationFn: async (input: { id: string; sort_order?: number; note?: string | null }) => {
      const patch: any = {};
      if (input.sort_order !== undefined) patch.sort_order = input.sort_order;
      if (input.note !== undefined) patch.note = input.note;
      const { error } = await supabase.from("nearby_food_pins").update(patch).eq("id", input.id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: PINS_QUERY_KEY });
      toast({ title: t("admin.nearbyFoodPins.updated") });
    },
    onError: (err: any) => toast({ title: err?.message || "Error", variant: "destructive" }),
  });

  const remove = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("nearby_food_pins").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: PINS_QUERY_KEY });
      toast({ title: t("admin.nearbyFoodPins.deleted") });
    },
    onError: (err: any) => toast({ title: err?.message || "Error", variant: "destructive" }),
  });

  return { list, add, update, remove };
}

/** Public hook used by landmark detail page to fetch all pins with restaurant geo info. */
export function useNearbyFoodPinsPublic() {
  return useQuery({
    queryKey: ["nearby-food-pins-public"],
    queryFn: async (): Promise<NearbyFoodPinRow[]> => {
      const { data, error } = await supabase
        .from("nearby_food_pins")
        .select("*, restaurants:restaurant_id (id,name,name_en,name_pt,image_url,lat,lng,city,address,visible,archived,store_level,template,type_en,michelin_stars)")
        .order("sort_order", { ascending: true });
      if (error) throw error;
      return (data || []) as any;
    },
    staleTime: 30_000,
  });
}
